export function hasAnimation() {
    if (!import.meta.env.SSR) {
        if (!window.matchMedia) {
            return true;
        }
        const mediaQuery = window.matchMedia('(prefers-reduced-motion: reduce)');
        return !(!mediaQuery || mediaQuery.matches);
    }
    return false;
}
